<template>
  <div class="panel panel-default">
    <div class="panel-heading">
      {{op.op}}
      <button class="btn btn-danger pull-right" @click="remove">
        <i class="fa fa-trash-o"></i>
      </button>
    </div>
    <div class="panel-body">
      <div class="row">
        <div class="col-md-4 col-sm-12">
          <div class="form-group">
            <label :for="op.data.name">Name</label>
            <input v-model="op.data.name" class="form-control"/>
          </div>
        </div>
        <div class="col-md-4 col-sm-12">
          <div class="form-group">
            <label :for="op.data.label">Label</label>
            <input v-model="op.data.label" class="form-control"/>
          </div>
        </div>
        <div class="col-md-4 col-sm-12">
          <div class="form-group">
            <label :for="op.data.expression">Expression</label>
            <input v-model="op.data.expression" class="form-control"/>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  name: 'Compute',
  props: ['op'],
  methods: {
    remove () {
      this.$emit('remove', this.op)
    }
  }
}
</script>

<style scoped>
 .btn {
   padding: 4px 10px;
   position: relative;
   top: -5px;
 }
 .col-md-4:not(:first-of-type) {
   padding-left: 4px;
 }
 .col-md-4:not(:last-of-type) {
   padding-right: 4px;
 }
</style>



