<template>
  <div class="panel panel-default">
    <div class="panel-heading">
      {{op.op}}
      <button class="btn btn-danger pull-right" @click="remove">
        <i class="fa fa-trash-o"></i>
      </button>
    </div>
    <div class="panel-body">
      <timeline-select-rule v-for="(rule, key, index) in op.data.rules" :key="key" :columns="columns" :rule="rule" :last="isLastRule(key)" @removeRule="removeRule">
      </timeline-select-rule>
      <div class="row">
        <div class="col-md-12 text-center">
          <button class="btn btn-default btn-add-or" @click="addRule">Add 'Or'</button>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import TimelineSelectRule from './timeline-select-rule'

export default {
  name: 'TimelineSelect',
  props: ['op', 'columns'],
  components: {
    TimelineSelectRule
  },
  watch: {
    columns (val) {
      console.log('columns updated')
    }
  },
  methods: {
    addRule () {
      this.$emit('addRule', this.op)
    },
    isLastRule (index) {
      return this.op.data.rules.length === (index + 1)
    },
    remove () {
      this.$emit('remove', this.op)
    },
    removeRule (rule) {
      this.$emit('removeRule', this.op, rule)
    }
  }
}
</script>

<style scoped>
 .btn {
   padding: 4px 10px;
   position: relative;
   top: -5px;
 }
</style>



